import pytest

DEFERRED_STATUSES = {"deferred", "pending", "blocked"}

def test_withdrawal_deferred_before_hold_expires(auth_headers, api_client, unique_biller_payload, cleanup_biller):
    payload = unique_biller_payload()
    reg = api_client.post("/billers", json=payload, headers=auth_headers)
    assert reg.status_code == 201
    biller_id = reg.json()["id"]
    cleanup_biller(payload["account_number"])

    withdrawal_payload = {"biller_id": biller_id, "amount": "1.00", "currency": "USD"}
    resp = api_client.post("/withdrawals", json=withdrawal_payload, headers=auth_headers)

    if resp.status_code == 202:
        status = resp.json().get("status", "").lower()
        assert status in DEFERRED_STATUSES, f"Expected deferred status, got: {status}"
    else:
        assert resp.status_code in (403, 422), (
            f"Expected 202/403/422 for held biller withdrawal, got {resp.status_code}"
        )
